  provider.models = form.models.map(m => ({ id: m.id, name: m.name, enabled: m.enabled, isCustom: m.isCustom }))
  try {
    await configStore.saveProviders()
    closeModal()
  } catch (e: any) {
    alert(e.message || '保存失败')
  }
}

